import (
	context "context"
	fern "github.com/multi-line-docs/fern"
	fernclient "github.com/multi-line-docs/fern/client"
)

client := fernclient.NewClient()
response, err := client.User.Createuser(
	context.TODO(),
	&fern.UserCreateUserRequest{
		Name: "name",
	},
)

